import React, { useRef } from 'react';

interface FileUploadProps {
  onFileSelected: (file: File) => void;
}

const FileUpload: React.FC<FileUploadProps> = ({ onFileSelected }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      onFileSelected(e.target.files[0]);
    }
  };

  const handleBoxClick = () => {
    fileInputRef.current?.click();
  };

  return (
    <div className="custom-upload-box" onClick={handleBoxClick}>
      <input
        type="file"
        accept=".pdf,.doc,.docx,.txt,application/pdf,application/vnd.openxmlformats-officedocument.wordprocessingml.document,application/msword,text/plain"
        className="file-input-hidden"
        ref={fileInputRef}
        onChange={handleFileChange}
      />
      <div className="upload-icon">📤</div>
      <div className="upload-text">Click or drag a file here to upload</div>
      <div className="upload-subtext">PDF, DOCX, or TXT</div>
    </div>
  );
};

export default FileUpload;
